  ('generalpolice-94737317-moex-00502', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '液壓千斤頂應用帕斯卡原理，亦即以較小的施力就可以舉起重物。若千斤頂大小活塞面積比為50：1， 在小活塞上施予10公斤重的力，則大活塞可舉起多少公斤重的物體？', '["100", "200", "300", "500"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "46a94943e2b1", "answer_pdf_sha1": "4509f4bde46a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
